package com.rozplochowski.coding.stack;

import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.Arguments;
import org.junit.jupiter.params.provider.MethodSource;

import java.util.stream.Stream;

import static org.junit.jupiter.api.Assertions.*;

class DecodeStringTest {

    @ParameterizedTest
    @MethodSource("cases")
    void shouldDecodeString(String input, String expected) {
        assertEquals(expected, DecodeString.decodeString(input));
    }

    private static Stream<Arguments> cases() {
        return Stream.of(
//                Arguments.of("3[a]2[bc]", "aaabcbc"),
                Arguments.of("3[a2[c]]", "accaccacc"),
                Arguments.of("2[abc]3[cd]ef", "abcabccdcdcdef"),
                Arguments.of("100[leetcode]", ""),
                Arguments.of("3[z]2[2[y]pq4[2[jk]e1[f]]]ef", "zzzyypqjkjkefjkjkefjkjkefjkjkefyypqjkjkefjkjkefjkjkefjkjkefef")
        );
    }

}